// Jen běžné zprávy s obsahem; přeskočí systémové subtype a prázdné pingy
const raw = $input.first().json;
const ev = raw.event || raw;
if (!ev || (ev.type && ev.type !== 'message')) return [];
const skip = new Set([
  'channel_join', 'channel_leave', 'group_join', 'message_changed', 'message_deleted',
  'channel_topic', 'channel_purpose', 'channel_archive', 'channel_unarchive',
  'pinned_item', 'unpinned_item', 'file_comment'
]);
if (ev.subtype && skip.has(ev.subtype)) return [];
if (ev.subtype === 'bot_message') return [];
if (!ev.channel) return [];

// Soubory: přímé uploady na zprávu + přílohy z forwardovaných unfurlů
const directFiles = Array.isArray(ev.files) ? ev.files : [];
const unfurlFiles = (Array.isArray(ev.attachments) ? ev.attachments : [])
  .flatMap((a) => (Array.isArray(a?.files) ? a.files : []));
const seen = new Set();
const files = [];
for (const f of [...directFiles, ...unfurlFiles]) {
  const key = f?.id || f?.url_private_download;
  if (!key || seen.has(key)) continue;
  seen.add(key);
  files.push(f);
}

const hasText = ev.text && String(ev.text).trim().length > 0;
const hasFiles = files.length > 0;
const hasAttachments = Array.isArray(ev.attachments) && ev.attachments.length > 0;
if (!hasText && !hasFiles && !hasAttachments) return [];
return [{ json: { channelId: ev.channel, slackEvent: ev, files } }];

// Fan-out: 1 zpráva → N items, jeden per příloha
const pack = $('Sloučit kontext').first().json;
const e = pack.slackEvent;
const files = pack.files || [];
const date = new Date(parseFloat(e.ts) * 1000);
const ts = `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}-${String(date.getDate()).padStart(2,'0')}-${String(date.getHours()).padStart(2,'0')}${String(date.getMinutes()).padStart(2,'0')}`;
return files.map((f, i) => {
  const safeName = String(f.name || 'unnamed').replace(/[\\/]/g, '_');
  const fileTag = f.id || `f${i}`;
  return {
    json: {
      file: f,
      ts,
      targetName: `${ts}-${fileTag}-${safeName}`.substring(0, 200)
    }
  };
});

const pack = $('Sloučit kontext').first().json;
const e = pack.slackEvent;
const channelId = pack.channelId;
const ch = $('Slack: Channel info').first().json;
const channelName = ch.name || channelId || 'unknown';

// Defensive: Aggregate přílohy běží jen ve větvi 'má přílohy = true'
let uploadedAttachments = [];
try {
  const agg = $('Aggregate přílohy').first();
  if (agg && agg.json && Array.isArray(agg.json.uploadedAttachments)) {
    uploadedAttachments = agg.json.uploadedAttachments;
  }
} catch (_) { /* žádné přílohy v této větvi */ }

const date = new Date(parseFloat(e.ts) * 1000);
const ts = `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}-${String(date.getDate()).padStart(2,'0')}-${String(date.getHours()).padStart(2,'0')}${String(date.getMinutes()).padStart(2,'0')}`;

const ownText = (e.text && String(e.text).trim()) ? String(e.text) : '';
const attachments = Array.isArray(e.attachments) ? e.attachments : [];
const forwards = attachments.filter(a => a && (a.is_msg_unfurl || a.from_url || a.text || a.fallback));

const slugSrc = ownText || (forwards[0] && (forwards[0].text || forwards[0].fallback)) || 'zprava';
const textSlug = String(slugSrc).replace(/[^a-z0-9 ]/gi,'').trim().replace(/\s+/g,'-').toLowerCase().substring(0, 50);
const filename = `${ts}-${channelName}-${textSlug || 'slack'}.md`.substring(0, 120);

const permalink = `https://slack.com/archives/${channelId}/p${String(e.ts).replace('.','')}`;
const threadNote = e.thread_ts && e.thread_ts !== e.ts ? `**Odpověď ve vlákně** (thread_ts: ${e.thread_ts})` : '';

const lines = [
  `# #${channelName}`,
  '',
  `**Čas:** ${date.toLocaleString('cs-CZ')}`,
  `**Uživatel (Slack ID):** ${e.user || '—'}`,
  threadNote,
  `**Odkaz:** ${permalink}`,
  ''
];

if (ownText) {
  lines.push('## Komentář', '', ownText, '');
}

if (forwards.length) {
  lines.push(`## Forwardovaný obsah${forwards.length > 1 ? ` (${forwards.length})` : ''}`, '');
  for (const a of forwards) {
    const author = a.author_name || a.author_subname || '—';
    const srcChannel = a.channel_name ? `#${a.channel_name}` : (a.channel_id || '');
    const srcLink = a.from_url || '';
    const srcTs = a.ts ? new Date(parseFloat(a.ts) * 1000).toLocaleString('cs-CZ') : '';
    const body = String(a.text || a.fallback || '').replace(/^\u200B+/, '').trim();
    lines.push(`### ${author}${srcChannel ? ` v ${srcChannel}` : ''}${srcTs ? ` (${srcTs})` : ''}`);
    if (srcLink) lines.push(`**Zdroj:** ${srcLink}`);
    lines.push('');
    lines.push(body || '_(prázdná příloha)_');
    lines.push('');
  }
}


// --- vlákna z Slack API ---
const ctx = $('Sloučit kontext').first().json;
const threadSections = ctx.threadSections || [];
if (threadSections.length) {
  lines.push('## Vlákno (Slack API)', '');
  for (const sec of threadSections) {
    const tag = sec.label === 'capture' ? 'capture kanál' : 'zdroj forwardu';
    lines.push(`### Thread ${sec.key} (${tag})`, '');
    for (const m of sec.messages) {
      const mDate = new Date(parseFloat(m.ts || 0) * 1000).toLocaleString('cs-CZ');
      const who = m.user || m.username || m.bot_id || '?';
      lines.push(`#### ${who} — ${mDate}`, '', String(m.text || '').trim() || '_(prázdné)_', '');
      if (Array.isArray(m.files) && m.files.length) {
        lines.push('**Soubory:**');
        for (const f of m.files) lines.push(`- ${f.name || f.id}`);
        lines.push('');
      }
    }
  }
}

if (uploadedAttachments.length) {
  lines.push(`## Přílohy${uploadedAttachments.length > 1 ? ` (${uploadedAttachments.length})` : ''}`, '');
  for (const a of uploadedAttachments) {
    const link = a.webViewLink || '';
    const name = a.name || '(bez jména)';
    const mime = a.mimeType || '';
    const sizeBytes = a.size ? parseInt(a.size, 10) : 0;
    const sizeStr = sizeBytes ? (sizeBytes >= 1024*1024 ? `${(sizeBytes/1048576).toFixed(1)} MB` : `${Math.max(1, Math.round(sizeBytes/1024))} kB`) : '';
    const meta = [mime, sizeStr].filter(Boolean).join(', ');
    lines.push(`- [${name}](${link})${meta ? ` — ${meta}` : ''}`);
  }
  lines.push('');
}

if (!ownText && !forwards.length && !uploadedAttachments.length) {
  lines.push('## Text', '', '_(bez textu — v původní zprávě mohou být jen přílohy)_', '');
}

const md = lines.join('\n');

return [{ json: { filename, content: md } }];

// Node: Sestav thready k načtení
// Jen vlákna v capture kanálu — bot nemá přístup do cizích kanálů/DM (conversations.replies → channel_not_found).
// Forwardovaný obsah je už v message attachments (## Forwardovaný obsah v Format → Markdown).

const pack = $input.first().json;
const ev = pack.slackEvent;
const threads = [];
const seen = new Set();

function addThread(channelId, threadTs, label) {
  if (!channelId || !threadTs) return;
  const key = `${channelId}:${threadTs}`;
  if (seen.has(key)) return;
  seen.add(key);
  threads.push({ channelId, threadTs, label });
}

if (ev.thread_ts) {
  addThread(ev.channel, ev.thread_ts, 'capture');
}

return [{ json: { ...pack, threadsToFetch: threads } }];

const pack = $input.first().json;
const threads = pack.threadsToFetch || [];
if (!threads.length) return [];
return threads.map((t) => ({
  json: {
    pack,
    threadChannelId: t.channelId,
    threadTs: t.threadTs,
    threadLabel: t.label,
  },
}));

const pack = $('Sestav thready k načtení').first().json;
const ev = pack.slackEvent;

const threadSections = [];
let replyItems = [];
try {
  const agg = $('Aggregate vlákno').first().json;
  const rows = Array.isArray(agg.threadMessages) ? agg.threadMessages : [];
  replyItems = rows.map((m) => ({ json: m }));
} catch (_) {
  replyItems = [];
}

const byThread = new Map();
for (const item of replyItems) {
  const m = item.json || {};
  const channel = m.channel || 'unknown';
  const parentTs = m.thread_ts || m.ts;
  const key = `${channel}:${parentTs}`;
  if (!byThread.has(key)) byThread.set(key, { messages: [], label: 'forward' });
  byThread.get(key).messages.push(m);
}

try {
  for (const item of $('Rozbal thready').all()) {
    const j = item.json || {};
    const key = `${j.threadChannelId}:${j.threadTs}`;
    if (byThread.has(key)) byThread.get(key).label = j.threadLabel || 'forward';
  }
} catch (_) {}

for (const [key, sec] of byThread) {
  const messages = [...sec.messages].sort((a, b) => parseFloat(a.ts || 0) - parseFloat(b.ts || 0));
  const label = sec.label || 'forward';
  let filtered = messages;
  if (label === 'capture') {
    const triggerTs = parseFloat(ev.ts || 0);
    filtered = messages.filter((m) => parseFloat(m.ts || 0) >= triggerTs);
    if (!filtered.length) filtered = messages;
  }
  threadSections.push({ key, label, messages: filtered });
}

function collectFiles(msgs) {
  const out = [];
  for (const m of msgs) {
    if (Array.isArray(m.files)) out.push(...m.files);
  }
  return out;
}

const directFiles = Array.isArray(ev.files) ? ev.files : [];
const unfurlFiles = (Array.isArray(ev.attachments) ? ev.attachments : [])
  .flatMap((a) => (Array.isArray(a?.files) ? a.files : []));
const threadFiles = threadSections.flatMap((s) => collectFiles(s.messages));

const seen = new Set();
const files = [];
for (const f of [...directFiles, ...unfurlFiles, ...threadFiles]) {
  const k = f?.id || f?.url_private_download;
  if (!k || seen.has(k)) continue;
  seen.add(k);
  files.push(f);
}

return [{
  json: {
    channelId: pack.channelId,
    slackEvent: ev,
    files,
    threadSections,
    threadsToFetch: pack.threadsToFetch || [],
  },
}];

